const F = "'Noto Sans KR',sans-serif";

function BackBtn({ onClick }) {
  return (
    <button onClick={onClick} style={{
      background:"none", border:"none",
      cursor:"pointer", display:"flex", alignItems:"center", gap:"6px",
      marginBottom:"20px", padding:"0",
    }}>
      <span style={{
        width:"32px", height:"32px",
        background:C.navyLight,
        borderRadius:"50%",
        display:"flex", alignItems:"center", justifyContent:"center",
        fontSize:"14px", color:C.navy, flexShrink:0,
        fontWeight:"900"
      }}>‹</span>
      <span style={{color:C.textSub, fontSize:"14px", fontWeight:"600", fontFamily:F}}>메인으로</span>
    </button>
  );
}

function Tag({ children, color=C.navy }) {
  return (
    <span style={{background:color,color:C.white,fontSize:"11px",fontWeight:"900",padding:"3px 10px",borderRadius:"20px",letterSpacing:"0.5px",fontFamily:F}}>{children}</span>
  );
}

function Card({ children, style={}, yellow=false }) {
  return (
    <div style={{
      background: yellow ? C.yellowBg : C.bgCard,
      border: `1px solid ${yellow ? C.borderY : C.border}`,
      borderRadius:"14px", padding:"18px", ...style
    }}>{children}</div>
  );
}

function SecTitle({ children }) {
  return <p style={{color:C.navy,fontSize:"18px",fontWeight:"900",margin:"0 0 14px",fontFamily:F}}>{children}</p>;
}

